@namespace sv_562120c44c7b455cb77bb92118999051.Components.Settings

<nav class="settings-sidebar">
    <h5 class="settings-sidebar-title">Settings</h5>
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li class="settings-nav-item">
                <button class="settings-nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="settings-nav-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    width: 220px;
    min-height: 100%;
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.settings-sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item {
    margin: 0;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    width: 100%;
    padding: 0.7rem 1.25rem;
    border: none;
    background: none;
    color: #495057;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    text-align: left;
}

.settings-nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.settings-nav-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

