@namespace sv_562120c44c7b455cb77bb92118999051.Components.Settings
@inject ISettingsService SettingsService

<div class="profile-section">
    <h3>Profile</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <div class="profile-avatar-area">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(_displayName))
                {
                    <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                }
                else
                {
                    <div class="avatar-placeholder">👤</div>
                }
            </div>
            <div class="avatar-url-display">
                <label class="form-label">Avatar URL</label>
                <input type="text" class="form-control form-control-sm" value="@_avatarUrl" readonly />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">
                Discard Changes
            </button>
        </div>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✓ Profile saved successfully!
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _savedProfile = profile;
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;

        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _showSuccess = false;
    }
}

.profile-section h3 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.profile-avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
}

.avatar-preview {
    flex-shrink: 0;
}

.avatar-img {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

.avatar-placeholder {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
}

.avatar-url-display {
    flex: 1;
    min-width: 0;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-5px); }
    to { opacity: 1; transform: translateY(0); }
}

@namespace sv_562120c44c7b455cb77bb92118999051.Components.Settings
@inject ISettingsService SettingsService

<div class="notifications-section">
    <h3>Notifications</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading preferences…</p>
    }
    else
    {
        <div class="toggle-group">
            <div class="toggle-item">
                <label class="toggle-label">
                    <input type="checkbox" class="form-check-input" @bind="_emailNotifications" />
                    <span>Email Notifications</span>
                </label>
                <span class="toggle-description">Receive notifications via email</span>
            </div>

            <div class="toggle-item">
                <label class="toggle-label">
                    <input type="checkbox" class="form-check-input" @bind="_pushNotifications" />
                    <span>Push Notifications</span>
                </label>
                <span class="toggle-description">Receive push notifications in your browser</span>
            </div>

            <div class="toggle-item">
                <label class="toggle-label">
                    <input type="checkbox" class="form-check-input" @bind="_weeklyDigest" />
                    <span>Weekly Digest</span>
                </label>
                <span class="toggle-description">Receive a weekly summary email</span>
            </div>
        </div>

        <hr />

        <h5>Muted Channels</h5>
        <p class="text-muted">Uncheck channels you want to mute.</p>

        @if (_allChannels.Count == 0)
        {
            <p class="text-muted fst-italic">No channels available.</p>
        }
        else
        {
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var isMuted = _mutedChannels.Contains(channel);
                    <label class="channel-item form-check">
                        <input type="checkbox"
                               class="form-check-input"
                               checked="@(!isMuted)"
                               @onchange="() => ToggleChannel(channel)" />
                        <span class="form-check-label">@channel</span>
                    </label>
                }
            </div>
        }

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✓ Notification preferences saved!
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);

        // Build channel list from muted channels plus some defaults
        _allChannels = ["General", "Announcements", "Engineering", "Marketing", "Support"];
        foreach (var ch in prefs.MutedChannels.Where(c => !_allChannels.Contains(c)))
        {
            _allChannels.Add(ch);
        }

        _loading = false;
    }

    private void ToggleChannel(string channel)
    {
        if (!_mutedChannels.Remove(channel))
        {
            _mutedChannels.Add(channel);
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;

        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());

        await SettingsService.SaveNotificationPrefsAsync(prefs);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

