    border-radius: 0.5rem;
}

.toggle-label {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    font-weight: 500;
    cursor: pointer;
    margin: 0;
}

.toggle-description {
    font-size: 0.85rem;
    color: #6c757d;
    margin-left: 2rem;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    max-height: 200px;
    overflow-y: auto;
    padding: 0.5rem;
