.notifications-section h3 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 1rem;
}

.toggle-item {
    display: flex;
    flex-direction: column;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
}

.toggle-label {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    font-weight: 500;
    cursor: pointer;
    margin: 0;
}

.toggle-description {
    font-size: 0.85rem;
    color: #6c757d;
    margin-left: 2rem;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    max-height: 200px;
    overflow-y: auto;
    padding: 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
}

.channel-item {
    padding: 0.25rem 0;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-5px); }
    to { opacity: 1; transform: translateY(0); }
}

