@namespace sv_562120c44c7b455cb77bb92118999051.Components.Settings
@inject ISettingsService SettingsService

<div class="security-section">
    <h3>Security</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button"
                 @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess)
                    {
                        <div class="alert alert-success py-2">✓ Password updated successfully!</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled"
                               @onchange="Toggle2FA" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted mt-2 mb-0" style="font-size: 0.85rem;">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
