@inject ISettingsService SettingsService

<div class="security-section">
    <h3>Security</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button"
                 @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess)
                    {
                        <div class="alert alert-success py-2">✓ Password updated successfully!</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled"
                               @onchange="Toggle2FA" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted mt-2 mb-0" style="font-size: 0.85rem;">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </p>
                }
            </div>
        </div>

        @* Active Sessions *@
        <div class="card">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="card-body p-0">
                @if (_sessions.Count == 0)
                {
                    <p class="text-muted p-3 mb-0">No active sessions.</p>
                }
                else
                {
                    <div class="table-responsive">
                        <table class="table table-hover mb-0">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th></th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var session in _sessions)
                                {
                                    <tr>
                                        <td>@session.Device</td>
                                        <td>@session.Location</td>
                                        <td>@session.LastActive.ToString("g")</td>
                                        <td>
                                            @if (session != _sessions.First())
                                            {
                                                <button class="btn btn-sm btn-outline-danger"
                                                        @onclick="() => PromptRevoke(session)">
                                                    Revoke
                                                </button>
                                            }
                                            else
                                            {
                                                <span class="badge bg-info">Current</span>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @(_revoking ? "Revoking…" : "Revoke Session")
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _passwordExpanded;
    private bool _changingPassword;
    private bool _passwordSuccess;
    private string _passwordError = "";

    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";

    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = "";
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)(e.Value ?? false);
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.Remove(_sessionToRevoke);
        _sessionToRevoke = null;
        _revoking = false;
    }
}
