@namespace sv_562120c44c7b455cb77bb92118999051.Components.Settings
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h3>Appearance</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                @* Theme Selector *@
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <label class="theme-option @(_theme == theme ? "selected" : "")">
                                <input type="radio" name="theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <span class="theme-label">@theme</span>
                            </label>
                        }
                    </div>
                </div>

                @* Font Size Selector *@
                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <label class="size-option @(_fontSize == size ? "selected" : "")">
                                <input type="radio" name="fontSize" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <span class="size-label">@size</span>
                            </label>
                        }
                    </div>
                </div>

                @* Language Dropdown *@
                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 250px;" @bind="_language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                @* Compact Mode *@
                <div class="mb-4">
                    <label class="form-check">
                        <input type="checkbox" class="form-check-input" @bind="_compactMode" />
                        <span class="form-check-label fw-medium">Compact Mode</span>
                    </label>
                    <span class="text-muted d-block" style="font-size: 0.85rem;">
                        Reduce spacing and padding throughout the interface
                    </span>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success mt-3 fade-in" role="alert">
                        ✓ Appearance settings saved!
                    </div>
                }
            </div>

            @* Live Preview *@
            <div class="col-md-5">
                <div class="preview-container @GetPreviewClasses()">
                    <h6 class="preview-title">Live Preview</h6>
                    <div class="preview-content">
                        <div class="preview-header">Dashboard</div>
                        <p class="preview-text">This is how your content will look with the selected settings.</p>
                        <div class="preview-card">
                            <div class="preview-card-title">Sample Card</div>
                            <div class="preview-card-body">Card content goes here</div>
                        </div>
                        <div class="preview-nav">
                            <span class="preview-nav-item active">Home</span>
                            <span class="preview-nav-item">Settings</span>
                            <span class="preview-nav-item">Help</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme.ToLowerInvariant()} preview-font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;

        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.appearance-section h3 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.theme-option,
.size-option {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1rem;
    border: 2px solid #dee2e6;
    border-radius: 0.5rem;
    cursor: pointer;
    transition: border-color 0.15s, background-color 0.15s;
}

.theme-option:hover,
.size-option:hover {
    border-color: #adb5bd;
}

.theme-option.selected,
.size-option.selected {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.theme-option input,
.size-option input {
    display: none;
}

.theme-label,
.size-label {
    font-weight: 500;
}

/* Preview area */
.preview-container {
    border: 1px solid #dee2e6;
    border-radius: 0.75rem;
    padding: 1.25rem;
    transition: all 0.3s ease;
    min-height: 280px;
}

.preview-title {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #6c757d;
    margin-bottom: 1rem;
}

.preview-header {
    font-weight: 700;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 1rem;
}

.preview-card {
    border: 1px solid;
    border-radius: 0.375rem;
    padding: 0.75rem;
    margin-bottom: 1rem;
}

.preview-card-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.preview-nav {
    display: flex;
    gap: 1rem;
    border-top: 1px solid;
    padding-top: 0.75rem;
}

.preview-nav-item {
    font-size: 0.9em;
    cursor: default;
}

.preview-nav-item.active {
    font-weight: 600;
}

/* Theme variations */
.preview-theme-light {
    background-color: #ffffff;
    color: #212529;
    border-color: #dee2e6;
}

.preview-theme-light .preview-card {
    border-color: #dee2e6;
    background-color: #f8f9fa;
}

.preview-theme-light .preview-nav {
    border-color: #dee2e6;
}

.preview-theme-dark {
    background-color: #1a1a2e;
    color: #e0e0e0;
    border-color: #3a3a5c;
}

.preview-theme-dark .preview-card {
    border-color: #3a3a5c;
    background-color: #16213e;
}

.preview-theme-dark .preview-nav {
    border-color: #3a3a5c;
}

.preview-theme-dark .preview-title {
    color: #9e9eb8;
}

.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1a2e 50%);
    color: #212529;
    border-color: #adb5bd;
}

.preview-theme-system .preview-card {
    border-color: #adb5bd;
    background-color: rgba(248, 249, 250, 0.8);
}

.preview-theme-system .preview-nav {
    border-color: #adb5bd;
}

/* Font size variations */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact {
    padding: 0.75rem;
}

.preview-compact .preview-card {
    padding: 0.4rem;
    margin-bottom: 0.5rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.5rem;
}

.preview-compact .preview-header {
    margin-bottom: 0.25rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-5px); }
    to { opacity: 1; transform: translateY(0); }
}

